15→    const [newPassword, setNewPassword] = useState('');
16→    const [confirmPassword, setConfirmPassword] = useState('');
17→    const [showCurrentPass, setShowCurrentPass] = useState(false);
18→    const [showNewPass, setShowNewPass] = useState(false);
19→    const [passwordLoading, setPasswordLoading] = useState(false);
20→    const [passwordError, setPasswordError] = useState('');
21→    const [passwordSuccess, setPasswordSuccess] = useState('');
22→
23→    // Email state
24→    const [newEmail, setNewEmail] = useState('');
25→    const [emailLoading, setEmailLoading] = useState(false);
26→    const [emailError, setEmailError] = useState('');
27→    const [emailSuccess, setEmailSuccess] = useState('');
28→
29→    const handleChangePassword = async (e) => {
30→        e.preventDefault();
31→        setPasswordError('');
32→        setPasswordSuccess('');
33→
34→        if (newPassword.length < 6) {
35→            return setPasswordError('New password must be at least 6 characters.');
36→        }
37→        if (newPassword !== confirmPassword) {
38→            return setPasswordError('Passwords do not match.');
39→        }
40→
41→        setPasswordLoading(true);
42→        try {
43→            if (!isRecovery) {
44→                // Verify current password
45→                const { error: signInError } = await supabase.auth.signInWithPassword({
46→                    email: session.user.email,
47→                    password: currentPassword,
48→                });
49→                if (signInError) {
50→                    setPasswordLoading(false);
51→                    return setPasswordError('Current password is incorrect.');
52→                }
53→            }
54→
55→            // Update to new password
56→            const { error: updateError } = await supabase.auth.updateUser({
57→                password: newPassword,
58→            });
59→            if (updateError) {
60→                setPasswordLoading(false);
61→                return setPasswordError(updateError.message);
62→            }
63→
64→            setPasswordSuccess('Password updated successfully.');
65→            setCurrentPassword('');
66→            setNewPassword('');
67→            setConfirmPassword('');
68→
69→            // Clear recovery param from URL
70→            if (isRecovery) {
71→                searchParams.delete('recovery');
72→                setSearchParams(searchParams, { replace: true });
73→            }
74→        } catch (err) {
75→            setPasswordError('Something went wrong. Please try again.');
76→        } finally {
77→            setPasswordLoading(false);
78→        }
79→    };
